-- 3. LEAD CAPTURE — Tunbridge Wells (layout: lead-gen)
-- =============================================================================
INSERT INTO local_content (
  service_slug, town_slug, intro_paragraph, local_context, competition_landscape,
  success_approach, local_stats, pain_points, solutions, faqs, layout_variant
) VALUES (
  'lead-capture',
  'tunbridge-wells',
  'Tunbridge Wells businesses invest heavily in attracting visitors — through premium shopfronts on The Pantiles, advertising in local publications, and building a presence in the community around Calverley Grounds and the Assembly Hall. But digital visitor capture is often an afterthought. Your website gets traffic from people searching for services in and around Tunbridge Wells, from Pembury to Langton Green, yet most of those visitors leave without a trace. No email, no enquiry, no way to follow up. In a town where the customer base is affluent, research-driven, and comparison-shopping across multiple providers before committing, losing anonymous visitors means losing revenue. We build lead capture systems for Tunbridge Wells businesses that work the way your audience actually behaves — offering genuine value in exchange for contact details, then nurturing those prospects through a sequence that respects their intelligence and earns their trust.',
  'The Tunbridge Wells economy is anchored by professional services, independent retail, and a growing hospitality sector concentrated around Camden Road and The Pantiles. The town attracts significant footfall from surrounding villages — Southborough, Pembury, Rusthall, and Bidborough — and functions as the commercial centre for a population that extends well beyond its 60,000 core residents. Mount Pleasant Road and Calverley Road house clusters of solicitors, accountants, and consultants who rely on steady enquiry flow. The London commuter demographic means residents are accustomed to sophisticated digital experiences and are wary of pushy sales tactics. The Pantiles and High Street serve as two distinct commercial centres with different customer profiles — boutique browsers versus everyday shoppers.',
  'Most Tunbridge Wells businesses have contact forms on their websites but very few have genuine lead capture systems. Professional services firms on Mount Pleasant Road typically rely on phone enquiries and personal referrals, leaving significant digital demand unfulfilled. Independent retailers on The Pantiles often have social media followings but no mechanism to convert followers into a contactable database. The few businesses using lead magnets tend to offer generic downloads that do not address the specific concerns of the Tunbridge Wells market.',
  'Our lead capture approach for Tunbridge Wells is designed around the deliberate, research-heavy buying behaviour that defines this market. We create high-value lead magnets that address specific local concerns — guides for business owners navigating the competitive Tunbridge Wells professional services market, or resources tailored to the independent retail landscape. The nurture sequences we build are unhurried and informative, matching the way Tunbridge Wells prospects prefer to be communicated with: professional, knowledgeable, and never desperate.',
  '{"population": 60000, "business_count": "3200+", "key_areas": ["The Pantiles", "Mount Pleasant Road", "Camden Road", "High Street", "Calverley Road", "Southborough"]}',
  '[
    {"title": "High-intent website visitors from Tunbridge Wells leave without converting", "description": "People are finding your website by searching for services in Tunbridge Wells, Pembury, Southborough, and surrounding areas. They spend time on your pages, they read your content, and then they leave. Without a lead capture system, you have no way to re-engage those visitors — they move on to the next search result and you never know they existed."},
    {"title": "Referral-dependent firms have no pipeline when word-of-mouth slows", "description": "Many professional services firms around Mount Pleasant Road and Calverley Road have built their client base on referrals and reputation. That works until it does not. A quiet quarter, a retiring referral partner, or a new competitor can expose the fragility of a pipeline you do not control. Lead capture builds a consistent, measurable source of new enquiries that you own."},
    {"title": "Your audience is too sophisticated for pop-ups and generic offers", "description": "Tunbridge Wells residents — particularly the London commuter demographic — are experienced internet users who dismiss lazy lead capture tactics instantly. Generic pop-ups offering ''10% off your first order'' or ''subscribe to our newsletter'' do not work with an audience that values substance and is quick to judge credibility."}
  ]',
  '[
    {"title": "Lead magnets crafted for the Tunbridge Wells buyer", "description": "We create lead magnets that directly address what your target customer in Tunbridge Wells actually wants to know. For a solicitor, that might be a guide to property purchase in the TN postcodes. For a boutique retailer, it could be early access to seasonal collections. The key is genuine value that positions your expertise for this specific market."},
    {"title": "Nurture sequences that respect a research-driven audience", "description": "Our email nurture sequences are designed for prospects who compare, evaluate, and take their time before committing. We build trust through informative, non-pushy content that references local context — the kind of communication a Tunbridge Wells professional expects from a credible business, not a hard sell."},
    {"title": "Multi-channel capture across search, social, and local", "description": "We implement lead capture across every channel your Tunbridge Wells audience uses — from your website and Google Business Profile through to social media and local event presence. Each channel feeds into a single system so you have a unified view of every prospect, regardless of where they first found you."}
  ]',
  '[
    {"question": "What kind of lead magnet works for professional services in Tunbridge Wells?", "answer": "The Tunbridge Wells professional services market responds best to lead magnets that demonstrate genuine expertise. We have seen strong results with guides that address specific local concerns — property transaction guides for solicitors, tax planning resources for accountants serving the commuter demographic, or business growth workshops for the independent sector. The key is specificity: generic content does not convert in this market."},
    {"question": "Will lead capture feel pushy to my customers?", "answer": "Not if it is done properly. The Tunbridge Wells audience is allergic to pushy sales tactics, and we design every lead capture element accordingly. That means well-timed, well-designed offers that exchange genuine value for contact details, followed by nurture sequences that inform rather than pressure. Our approach is built around earning trust, which is the currency that actually works in this town."},
    {"question": "How quickly will I start seeing leads?", "answer": "If your website already receives traffic from Tunbridge Wells searches, you can start capturing leads within days of implementation. The speed depends on your traffic volume and how well-targeted the lead magnet is. Professional services firms typically see their first qualified leads within two to four weeks. Retail and hospitality businesses with higher traffic often see results faster."},
    {"question": "Can lead capture integrate with my existing CRM or booking system?", "answer": "Yes. We integrate with all major CRM platforms, practice management systems used by Tunbridge Wells solicitors and accountants, and booking tools used by hospitality and wellness businesses. The data flows automatically so your team does not need to manually transfer contacts. Everything is designed to slot into your existing workflow without adding administrative burden."}
  ]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
