-- =============================================================================
-- 6. SOCIAL MEDIA SETUP — Tunbridge Wells (layout: trust)
-- =============================================================================
INSERT INTO local_content (
  service_slug, town_slug, intro_paragraph, local_context, competition_landscape,
  success_approach, local_stats, pain_points, solutions, faqs, layout_variant
) VALUES (
  'social-media-setup',
  'tunbridge-wells',
  'Social media in Tunbridge Wells is not a megaphone — it is a conversation with a community that already has strong opinions about the businesses it supports. The town''s independent character, from The Pantiles boutiques to the Camden Road food scene, means local audiences actively follow and engage with businesses they consider part of the fabric of the town. But having social media profiles is not the same as having a social media presence. Many Tunbridge Wells businesses have dormant or inconsistent accounts that project uncertainty rather than confidence. Others post sporadically without strategy, generating activity but not results. We set up and structure social media for Tunbridge Wells businesses so that every profile, every bio, every content pillar is built for the specific audience in this area — affluent, digitally active, community-minded, and quick to unfollow anything that feels inauthentic. The result is a social presence that builds local trust and drives genuine enquiries.',
  'Tunbridge Wells has an unusually engaged local social media community. Town-focused Facebook groups, Instagram accounts showcasing The Pantiles and the Common, and local food bloggers covering Camden Road restaurants create a digital conversation that mirrors the strong community identity of the physical town. Events at Calverley Grounds, performances at the Assembly Hall Theatre and Trinity Theatre, and seasonal markets on The Pantiles generate regular content moments. The population of around 60,000 is supplemented by active social media users in Southborough, Pembury, Rusthall, and Langton Green who consider Tunbridge Wells their hub. The commuter demographic — London professionals living locally — tends to be active on LinkedIn and Instagram, creating opportunities for B2B businesses that most Kent towns do not offer.',
  'Social media presence among Tunbridge Wells businesses is patchy. Hospitality businesses on Camden Road and The Pantiles generally maintain active Instagram profiles, leveraging the visual appeal of their locations. Professional services firms tend to have LinkedIn pages that are rarely updated. Independent retailers range from highly engaged to completely dormant. Few businesses in the town have a cohesive multi-platform strategy, and even fewer integrate their social presence with lead capture or website traffic goals. The businesses that do social media well in Tunbridge Wells tend to thrive because the audience is eager to engage with authentic local content.',
  'We build social media foundations for Tunbridge Wells businesses by working outward from your specific position in the local market. A solicitors'' firm on Mount Pleasant Road needs a LinkedIn strategy focused on professional authority and local business networking. A boutique on The Pantiles needs an Instagram presence that captures the aesthetic appeal of the location and the product range. We configure each platform with locally optimised profiles, establish content pillars that reflect the Tunbridge Wells audience''s interests, and create a content calendar that connects to the town''s rhythm of events, seasons, and community moments.',
  '{"population": 60000, "business_count": "3200+", "key_areas": ["The Pantiles", "Camden Road", "Mount Pleasant Road", "Calverley Grounds", "High Street", "Assembly Hall Theatre"]}',
  '[
    {"title": "Your social profiles were set up years ago and now look abandoned", "description": "Many Tunbridge Wells businesses created social media accounts when someone told them they should, posted a few times, and then let them go dormant. In a town where the audience actively checks social media before visiting a business — especially on The Pantiles and Camden Road — a neglected profile does more damage than no profile at all. It signals that the business is either struggling or does not care about its public image."},
    {"title": "You are posting content but it is not reaching the local audience that matters", "description": "Some Tunbridge Wells business owners are posting regularly but seeing minimal engagement from local customers. The problem is usually structural: profiles not optimised for local discovery, content not tagged or geolocated to Tunbridge Wells, and no strategy for connecting with the local community accounts, food bloggers, and event pages that drive real engagement in this area."},
    {"title": "Your professional services firm has no LinkedIn presence in a commuter town", "description": "Tunbridge Wells has a high concentration of London-commuting professionals who are active on LinkedIn. For solicitors, accountants, financial advisers, and consultants in the town, LinkedIn is not optional — it is where your potential clients are professionally active. Yet most professional firms in the TN area have either no LinkedIn company page or one that has not been updated in months."}
  ]',
  '[
    {"title": "Platform-specific setup tailored to your Tunbridge Wells market position", "description": "We set up each social platform with your specific audience in mind. For consumer-facing businesses on The Pantiles and Camden Road, that means Instagram optimised for local discovery with curated visual templates. For professional services, it means a LinkedIn presence built for the commuter-professional demographic. Every bio, every category, every link is configured to attract the right Tunbridge Wells audience."},
    {"title": "Content pillars built around the Tunbridge Wells community rhythm", "description": "We establish content pillars that connect your business to the life of the town — seasonal events at Calverley Grounds, Pantiles market days, Assembly Hall shows, and the broader rhythm of Tunbridge Wells community life. This is not about jumping on trends; it is about being part of the conversation your local audience is already having."},
    {"title": "Local engagement strategy connecting you to the digital community", "description": "We map the local social media ecosystem — the Tunbridge Wells community groups, food bloggers, local photographers, event pages, and influencer accounts — and build an engagement strategy that connects your business to these existing conversations. Authentic local engagement generates more visibility and trust than any amount of paid promotion in a community-minded town like Tunbridge Wells."}
  ]',
  '[
    {"question": "Which social media platforms matter most for Tunbridge Wells businesses?", "answer": "It depends on your business type. For hospitality and retail on The Pantiles and Camden Road, Instagram is the primary platform — the visual appeal of these locations makes Instagram a natural fit and the local audience actively uses it for discovery. For professional services around Mount Pleasant Road, LinkedIn is essential for credibility and networking. Facebook remains relevant for reaching the broader community, particularly through Tunbridge Wells-focused groups. We recommend no more than two or three platforms, done well."},
    {"question": "How do you make social media work for professional firms in Tunbridge Wells?", "answer": "Professional services firms benefit most from a structured LinkedIn strategy that positions key individuals as knowledgeable voices in their field, combined with locally relevant content that demonstrates community involvement. In a town like Tunbridge Wells, where many clients choose their solicitor or accountant through personal and professional networks, LinkedIn builds the familiarity and credibility that precedes referrals. We set this up with content templates and a posting calendar that your team can sustain without it becoming a second job."},
    {"question": "Can social media actually drive customers to a physical Tunbridge Wells location?", "answer": "Absolutely, and we see it consistently. The Tunbridge Wells social media audience actively uses Instagram and Facebook to decide where to eat on Camden Road, which shops to visit on The Pantiles, and which professionals to contact. Geotagged content, local hashtags, and engagement with community accounts directly drive footfall. For a Spa Valley Railway event or a Calverley Grounds market, social media is often the primary discovery channel."},
    {"question": "I do not have time to post on social media regularly — how does this work?", "answer": "Our setup service includes creating a content framework and template system that makes posting fast and consistent. We also build a content calendar mapped to Tunbridge Wells events and seasonal moments, so you always know what to post. The goal is to reduce the effort from hours of deliberation per week to 15-20 minutes of execution. For businesses that want fully managed social media, we offer that as an ongoing service."}
  ]',
  'trust'
)
