-- 7. DIGITAL MARKETING — Tunbridge Wells (layout: lead-gen)
-- =============================================================================
INSERT INTO local_content (
  service_slug, town_slug, intro_paragraph, local_context, competition_landscape,
  success_approach, local_stats, pain_points, solutions, faqs, layout_variant
) VALUES (
  'digital-marketing',
  'tunbridge-wells',
  'Digital marketing in Tunbridge Wells requires a different playbook to most Kent towns. The audience here is more affluent, more digitally literate, and more sceptical of marketing that talks down to them. London commuters who make up a significant proportion of the population have seen every tactic — they scroll past generic ads, ignore template emails, and judge businesses that look like they bought followers. At the same time, the strong independent business scene creates genuine opportunities for brands that show up authentically in the digital spaces where Tunbridge Wells residents spend their time. Whether you are a professional services firm on Mount Pleasant Road trying to reach high-net-worth clients, a restaurant on Camden Road competing for the Friday evening booking, or a retailer on The Pantiles building an audience beyond the town, your digital marketing needs to be as considered and as quality-driven as the products and services you offer. We build digital marketing strategies for Tunbridge Wells businesses that respect the audience and deliver measurable results.',
  'Tunbridge Wells occupies a distinctive position in Kent''s economic landscape. With household incomes significantly above the county average and a population that commutes to London for senior professional roles, the town''s consumer behaviour mirrors parts of South West London more than it does neighbouring Kent towns. The Pantiles, with its artisan markets and independent galleries, positions Tunbridge Wells as a lifestyle destination. Camden Road has become a dining corridor that attracts visitors from across the region. The Assembly Hall Theatre and Trinity Theatre sustain a cultural audience. Calverley Grounds hosts events that draw thousands. The surrounding villages — Southborough, Pembury, Rusthall, Langton Green — extend the addressable market for any business with a digital presence. The TN1 through TN4 postcodes represent one of the highest-value advertising audiences in Kent.',
  'Digital marketing adoption among Tunbridge Wells businesses varies enormously. Some hospitality and lifestyle brands run sophisticated Instagram campaigns that generate genuine buzz. Meanwhile, many professional services firms rely entirely on referrals and word of mouth, treating digital marketing as an afterthought. Google Ads competition for legal and financial services keywords in the Tunbridge Wells area is expensive, with London firms and national brands bidding for the same affluent audience. The businesses that succeed are those that combine paid reach with organic credibility — a strategy most local competitors do not execute consistently.',
  'Our approach to digital marketing in Tunbridge Wells starts with the insight that this audience rewards quality and penalises anything that feels lazy or generic. We build campaigns that lead with genuine value — informative content, useful resources, authentic storytelling — rather than discount-driven advertising. For the commuter audience, we time campaigns around their daily patterns: early morning, lunchtime, and the evening commute from London Bridge. For the broader Tunbridge Wells community, we tie marketing activity to the rhythm of town life — The Pantiles events, seasonal moments at Calverley Grounds, and the weekly pulse of Camden Road.',
  '{"population": 60000, "business_count": "3200+", "key_areas": ["The Pantiles", "Camden Road", "Mount Pleasant Road", "Calverley Grounds", "High Street", "Southborough", "Pembury"]}',
  '[
    {"title": "Expensive Google Ads campaigns that attract clicks but not the right customers", "description": "Tunbridge Wells is an expensive area for paid search, especially for professional services and premium retail. Many businesses are spending heavily on Google Ads but attracting clicks from outside the area, from people comparing prices, or from searchers who are not ready to buy. In a market where customer acquisition costs are already high, wasted ad spend is a serious problem."},
    {"title": "Your referral pipeline is strong but not growing", "description": "Referrals have built many of Tunbridge Wells'' most successful professional firms. But relying solely on referrals creates a ceiling on growth and leaves you vulnerable when referral sources retire, relocate, or simply slow down. Digital marketing does not replace referrals — it supplements them by creating a parallel pipeline of qualified enquiries from the same demographic, reached through different channels."},
    {"title": "Generic digital marketing agencies do not understand the Tunbridge Wells buyer", "description": "Several Tunbridge Wells businesses have told us about disappointing experiences with marketing agencies — both London firms and remote agencies — that applied templated strategies without understanding the local market. Running the same Facebook ad campaign you would run in Maidstone or Ashford does not work in a town where the audience is wealthier, more digitally sophisticated, and expects a higher standard of communication."}
  ]',
  '[
    {"title": "Audience-first strategy for the Tunbridge Wells demographic", "description": "We build every campaign around detailed audience profiles specific to Tunbridge Wells. That means understanding the London commuter who researches services on the train, the affluent retiree browsing The Pantiles on a Tuesday morning, and the young professional couple exploring Camden Road on a Saturday evening. Different audiences, different channels, different messages — all within the same town."},
    {"title": "Integrated campaigns across search, social, and email", "description": "We run coordinated campaigns across Google, social media, and email that reinforce each other. A prospect who sees your Google ad also encounters your content on social media and receives a valuable email sequence. This multi-touchpoint approach is particularly effective in Tunbridge Wells where the research-heavy buyer needs multiple interactions before committing to a purchase or enquiry."},
    {"title": "Performance tracking with transparent, meaningful metrics", "description": "We provide clear reporting that focuses on the metrics that actually matter to your Tunbridge Wells business — qualified enquiries, cost per acquisition, and return on marketing spend. Not vanity metrics like impressions and reach that look impressive but do not indicate whether your marketing is generating revenue. Every pound of your marketing budget is tracked back to measurable business outcomes."}
  ]',
  '[
    {"question": "How much should a Tunbridge Wells business spend on digital marketing?", "answer": "It depends on your sector and goals, but the key principle is that Tunbridge Wells is a premium market. Competing for visibility here — particularly in professional services or premium hospitality — requires investment that matches the value of the customers you are targeting. A solicitor acquiring a single conveyancing client through digital marketing can generate thousands in fees, which makes the cost per acquisition equation very different to a volume business. We recommend budgets based on realistic ROI projections for your specific sector in this market."},
    {"question": "Which digital marketing channels work best in Tunbridge Wells?", "answer": "For professional services, Google search remains the highest-intent channel, supplemented by LinkedIn for building professional visibility. For hospitality and lifestyle businesses on Camden Road and The Pantiles, Instagram and local Facebook groups drive both awareness and footfall. Email marketing performs exceptionally well across all sectors in Tunbridge Wells because the audience prefers informed decision-making. We recommend a channel mix based on where your specific customers spend their time."},
    {"question": "Can you help with marketing to the surrounding villages as well as Tunbridge Wells itself?", "answer": "Yes, and this is important. A significant proportion of customers for Tunbridge Wells businesses live in Southborough, Pembury, Rusthall, Langton Green, and Bidborough. We build campaigns that target the wider TN postcode area with messaging that acknowledges the connection between these communities and Tunbridge Wells as their commercial centre. This expands your reach without diluting relevance."},
    {"question": "How do you measure success for digital marketing?", "answer": "We agree on specific KPIs at the start of every campaign — typically cost per lead, conversion rate, and return on ad spend. For professional services in Tunbridge Wells, we track the journey from first click through to client acquisition. For retail and hospitality, we measure website traffic, booking conversions, and footfall attribution where possible. Monthly reporting is transparent and focused on the numbers that affect your bottom line, not dashboard metrics that look good but mean nothing."}
  ]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
